import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"孤城剑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/孤城剑.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/孤城剑.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/孤城剑.md"};function p(l,e,_,i,c,h){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"孤城剑",tabindex:"-1"},[n("孤城剑 "),a("a",{class:"header-anchor",href:"#孤城剑","aria-label":'Permalink to "孤城剑"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),o('<h1 id="孤城剑-1" tabindex="-1">孤城剑 <a class="header-anchor" href="#孤城剑-1" aria-label="Permalink to &quot;孤城剑&quot;">​</a></h1><p>孤城 D+750<br> 剑柄裹着白色的皮革，十字护手则是锯齿型城墙的形状，剑刃上也带有坚硬而有光泽的锯齿。<br> 孤城是一把具有8L，威猛2，高速1，力量需求3的精金长剑，当面对相应的伤害减免时视为精金材质。<br> 使用要求：非黑暗生物，剑3，社交3</p><p>不详征兆：若用这把剑砍中了一个无辜的生物（具体由ST裁定，一般指道德值7以上的生物），那么剑身将不会粘上血，持有者因这不道德的行为而心怀愧疚，受到5DP士气减值，亦无法发动领导攻击。<br> 直到使用者完成赎罪或将剑彻底丢弃，这个效果才会结束。这是一个D级诅咒效果。</p><p>专属剑技-领导攻击 D+500<br> 你勇猛地向对手发动攻击。当你攻击时，你发出呐喊宣示胜利已在眼前。你的攻击可以激励周围的同伴参与战斗，让他们重新焕发精力。<br> 在你使用普通近战攻击时，若攻击命中，则你周围5米的队友在1回合内对你击中的目标进行下次攻击时，可以获得4DP士气加值，与其他群体增益类加值不叠加。</p><p>花费C+1250升级，技能效果替换为：<br> 使用标准动作发动一次近战白刃攻击，若攻击命中，周围3.25米的队友在1个场景内对你击中的目标进行攻击时，可以获得6DP士气加值。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{D as __pageData,m as default};
